     1→package com.grl.component.mapper;
     2→
     3→import com.grl.component.asg.configuration.YamlConfig;
     4→import com.grl.component.owl.OntologyUtil;
     5→import io.swagger.v3.oas.models.media.Schema;
     6→import java.util.Collections;
     7→import java.util.HashSet;
     8→import java.util.Map;
     9→import java.util.Set;
    10→import java.util.concurrent.ConcurrentSkipListMap;
    11→import org.semanticweb.owlapi.apibinding.OWLManager;
    12→import org.semanticweb.owlapi.model.IRI;
    13→import org.semanticweb.owlapi.model.OWLClass;
    14→import org.semanticweb.owlapi.model.OWLOntology;
    15→import org.semanticweb.owlapi.model.OWLOntologyManager;
    16→
    17→public class MappingContext {
    18→  private final String defaultOntologyPrefixIRI;
    19→  private final OWLOntology ontology;
    20→  private final OWLOntologyManager manager = OWLManager.createOWLOntologyManager();
    21→
    22→  private final Map<String, Schema<?>> schemaByRef = new ConcurrentSkipListMap<>(); // so we can safely computeIfAbsent
    23→  private final Set<String> computing = new HashSet<>();
    24→  private final String schemaLabel;
    25→
    26→  private final OWLClass apiRootClass;
    27→
    28→  private final Set<OWLClass> resourceClasses;
    29→
    30→  private final YamlConfig config;
    31→
    32→  public MappingContext(String defaultOntologyPrefixIRI, OWLOntology ontology, String schemaLabel,
    33→                        OWLClass apiRootClass, Set<OWLClass> resourceClasses, YamlConfig config) {
    34→    this.defaultOntologyPrefixIRI = defaultOntologyPrefixIRI;
    35→    this.ontology = ontology;
    36→    this.schemaLabel = schemaLabel;
    37→    this.apiRootClass = apiRootClass;
    38→    this.resourceClasses = Collections.unmodifiableSet(resourceClasses);
    39→    this.config = config;
    40→  }
    41→
    42→  public YamlConfig getConfig() {
    43→    return config;
    44→  }
    45→
    46→  public OWLClass getApiRootClass() {
    47→    return apiRootClass;
    48→  }
    49→
    50→  public String getDefaultOntologyPrefixIRI() {
    51→    return defaultOntologyPrefixIRI;
    52→  }
    53→
    54→  public OWLOntology getOntology() {
    55→    return ontology;
    56→  }
    57→
    58→
    59→  public String getSchemaLabel() {
    60→    return schemaLabel;
    61→  }
    62→
    63→  public Map<String, Schema<?>> getSchemaByRef() {
    64→    return schemaByRef;
    65→  }
    66→
    67→  public OWLOntologyManager getManager() {
    68→    return manager;
    69→  }
    70→
    71→
    72→  /**
    73→   * If not in context cache already, create schema for given class and add to cache
    74→   *
    75→   * @param shortName shortname of class
    76→   */
    77→  public void addSchema(String shortName) {
    78→    schemaByRef.computeIfAbsent(shortName, s -> {
    79→      if (!computing.contains(s)) {
    80→        computing.add(s);
    81→        OWLClass cls = manager.getOWLDataFactory().getOWLClass(IRI.create(defaultOntologyPrefixIRI + shortName));
    82→        String description = OntologyUtil.getDescription(cls, ontology);
    83→        ResourceSchemaMapper resourceSchemaMapper = new ResourceSchemaMapper(this, cls, description);
    84→        computing.remove(s);
    85→        return resourceSchemaMapper.getSchema();
    86→      } else
    87→        return null; // already being computed, ignore to avoid infinite recursion
    88→    });
    89→  }
    90→
    91→  public Set<OWLClass> getResourceClasses() {
    92→    return resourceClasses;
    93→  }
    94→
    95→
    96→}
